  depends_on "node@22"

  def install
    libexec.install Dir["*"]

    # Create a wrapper script that invokes the CLI via node
    (bin/"nesbot").write <<~EOS
      #!/usr/bin/env bash
      exec "#{Formula["node@22"].opt_bin}/node" "#{libexec}/bin/nesbot.js" "$@"
    EOS
  end

  test do
    # Verify the CLI starts and can init a repo
    system bin/"nesbot", "init", "--repo", testpath/"test-repo"
    assert_predicate testpath/"test-repo/.nesbot/config.json", :exist?
  end
